// ============================================================
// GA4 WEEKLY REPORT v9 — ALL ALIGNMENT FIXED
// AppStoneLab Technologies
// ============================================================

// ── 1. PULL DATA ─────────────────────────────────────────────

const currentWeek  = $('GA4 - Overview Current Week').first().json;
const previousWeek = $('GA4 - Overview Previous Week').first().json;

const pages = $('GA4 - Top 5 Pages').all()
  .map(i => i.json)
  .map(p => ({ ...p, unifiedScreenName: (!p.unifiedScreenName || p.unifiedScreenName === '') ? '(empty)' : p.unifiedScreenName }))
  .slice(0, 5);

const pagesPrev = $('GA4 - Top 5 Pages Previous Week').all()
  .map(i => i.json)
  .map(p => ({ ...p, unifiedScreenName: (!p.unifiedScreenName || p.unifiedScreenName === '') ? '(empty)' : p.unifiedScreenName }));

const referrals = $('GA4 - Top 5 Referrals').all()
  .map(i => i.json)
  .map(r => ({ ...r, sessionSourceMedium: r.sessionSourceMedium === '(direct) / (none)' ? 'Direct / App Open' : (r.sessionSourceMedium || 'Direct / App Open') }));

const referralsPrev = $('GA4 - Top 5 Referrals Previous Week').all()
  .map(i => i.json)
  .map(r => ({ ...r, sessionSourceMedium: r.sessionSourceMedium === '(direct) / (none)' ? 'Direct / App Open' : (r.sessionSourceMedium || 'Direct / App Open') }));

const countries     = $('GA4 - Top 5 Countries').all().map(i => i.json);
const countriesPrev = $('GA4 - Top 5 Countries Previous Week').all().map(i => i.json);
const devices       = $('GA4 - Device Breakdown').all().map(i => i.json);
const devicesPrev   = $('GA4 - Device Breakdown Previous Week').all().map(i => i.json);
const newVsRet      = $('New vs Returning Users Breakdown').all().map(i => i.json);
const newVsRetPrev  = $('GA4 - New vs Returning Previous Week').all().map(i => i.json);

const EXCLUDE_EVENTS = ['first_visit','first_open','page_view','app_remove','os_update','app_update','app_store_refund'];
const events     = $('GA4 - Top 5 Events').all().map(i => i.json).filter(e => !EXCLUDE_EVENTS.includes(e.eventName)).slice(0, 5);
const eventsPrev = $('GA4 - Top 5 Events Previous Week').all().map(i => i.json).filter(e => !EXCLUDE_EVENTS.includes(e.eventName));

// Gemini
let aiSummary = '';
try {
  const g = $('Generate AI Summary').first().json;
  aiSummary = g.content?.parts?.[0]?.text || g.text || g.output || g.response || g.message?.content || g.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch(e) { aiSummary = ''; }
aiSummary = typeof aiSummary === 'string' ? aiSummary : '';

let formattedAiSummary = '';
if (aiSummary.trim().length > 0) {
  const lines = aiSummary.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  const items = lines.map(l => `<li style="margin-bottom:10px;padding-left:4px;">${l.replace(/^[\*\-•]\s*/, '')}</li>`).join('');
  formattedAiSummary = `<ul style="margin:0;padding-left:18px;font-family:Georgia,serif;font-size:13.5px;color:#3D3530;line-height:1.7;">${items}</ul>`;
}

// ── 2. HELPERS ───────────────────────────────────────────────

function wowChange(current, previous) {
  const c = parseFloat(current), p = parseFloat(previous);
  if (!p || p === 0) return { text: 'N/A', color: '#9CA3AF', arrow: '—', pill: '#F3F4F6', pillText: '#6B7280' };
  const pct = ((c - p) / p) * 100;
  const up = pct >= 0;
  return { text: (up ? '+' : '') + pct.toFixed(1) + '%', color: up ? '#2D6A4F' : '#B91C1C', arrow: up ? '↑' : '↓', pill: up ? '#ECFDF5' : '#FEF2F2', pillText: up ? '#2D6A4F' : '#B91C1C' };
}

function wowChangeBounce(current, previous) {
  const c = parseFloat(current), p = parseFloat(previous);
  if (!p || p === 0) return { text: 'N/A', color: '#9CA3AF', arrow: '—', pill: '#F3F4F6', pillText: '#6B7280' };
  const pct = ((c - p) / p) * 100;
  const isGood = pct <= 0;
  return { text: (pct >= 0 ? '+' : '') + pct.toFixed(1) + '%', color: isGood ? '#2D6A4F' : '#B91C1C', arrow: isGood ? '↓' : '↑', pill: isGood ? '#ECFDF5' : '#FEF2F2', pillText: isGood ? '#2D6A4F' : '#B91C1C' };
}

function listWoWWithPrev(currItem, prevItems, nameField, valueField) {
  const prev = prevItems.find(p => p[nameField] === currItem[nameField]);
  const currVal = parseInt(currItem[valueField] || 0);
  if (!prev) return { wow: { text: 'New', arrow: '★', pill: '#FBF5EB', pillText: '#C9A96E' }, prevValue: null };
  const prevVal = parseInt(prev[valueField] || 0);
  if (!prevVal || prevVal === 0) return { wow: { text: 'New', arrow: '★', pill: '#FBF5EB', pillText: '#C9A96E' }, prevValue: null };
  const pct = ((currVal - prevVal) / prevVal) * 100;
  const up = pct >= 0;
  return {
    wow: { text: (up ? '+' : '') + pct.toFixed(1) + '%', arrow: up ? '↑' : '↓', pill: up ? '#ECFDF5' : '#FEF2F2', pillText: up ? '#2D6A4F' : '#B91C1C' },
    prevValue: prevVal,
  };
}

function formatDuration(s) {
  const sec = parseFloat(s);
  if (isNaN(sec)) return '0s';
  const m = Math.floor(sec / 60), r = Math.round(sec % 60);
  return m > 0 ? `${m}m ${r}s` : `${r}s`;
}
function fmt(n) { const num = parseInt(n); return isNaN(num) ? '0' : num.toLocaleString('en-IN'); }
function fmtPct(n) { return (parseFloat(n) * 100).toFixed(1) + '%'; }

// ── 3. WoW ───────────────────────────────────────────────────

const wow = {
  totalUsers:  wowChange(currentWeek.totalUsers,          previousWeek.totalUsers),
  sessions:    wowChange(currentWeek.sessions,            previousWeek.sessions),
  newUsers:    wowChange(currentWeek.new_users,           previousWeek.new_users),
  bounceRate:  wowChangeBounce(currentWeek.bounce_rate,   previousWeek.bounce_rate),
  avgDuration: wowChange(currentWeek.average_session_dur, previousWeek.average_session_dur),
};

const newUsersRow     = newVsRet.find(r => r.newVsReturning === 'new')           || { totalUsers: 0 };
const returningRow    = newVsRet.find(r => r.newVsReturning === 'returning')     || { totalUsers: 0 };
const newUsersPrevRow = newVsRetPrev.find(r => r.newVsReturning === 'new')       || { totalUsers: 0 };
const retUsersPrevRow = newVsRetPrev.find(r => r.newVsReturning === 'returning') || { totalUsers: 0 };
const totalNvR        = (parseInt(newUsersRow.totalUsers) + parseInt(returningRow.totalUsers)) || 1;
const wowNewUsers     = wowChange(newUsersRow.totalUsers,  newUsersPrevRow.totalUsers);
const wowRetUsers     = wowChange(returningRow.totalUsers, retUsersPrevRow.totalUsers);
const totalDeviceSessions = devices.reduce((s, d) => s + parseInt(d.sessions || 0), 0) || 1;

const startLabel     = $now.minus({days: 7}).toFormat('MMM dd, yyyy');
const endLabel       = $now.minus({days: 1}).toFormat('MMM dd, yyyy');
const prevStartLabel = $now.minus({days: 14}).toFormat('MMM dd');
const prevEndLabel   = $now.minus({days: 8}).toFormat('MMM dd');

// ── 4. DESIGN TOKENS ─────────────────────────────────────────

const C = {
  bg: '#F7F5F2', card: '#FFFFFF', headerBg: '#1C1C1C', headerSub: '#A89880',
  gold: '#C9A96E', sectionText: '#1C1C1C', label: '#6B6560', value: '#1C1C1C',
  prevValue: '#B0A89E', rowAlt: '#FDFCFB', rowBase: '#FFFFFF', divider: '#EDE8E2',
  footerBg: '#1C1C1C', footerText: '#6B6560',
};

// ── 5. HTML COMPONENTS ───────────────────────────────────────

const sectionGap = `<tr><td colspan="5" style="padding:8px 0;background:${C.bg};font-size:0;line-height:0;">&nbsp;</td></tr>`;

const sectionHeader = (title, subtitle) => `
<tr><td colspan="5" style="padding:0;">
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr><td style="padding:18px 24px 13px;border-bottom:2px solid ${C.gold};background:${C.card};">
      <span style="font-family:Georgia,serif;font-size:15px;font-weight:bold;color:${C.sectionText};letter-spacing:0.3px;">${title}</span>
      ${subtitle ? `<span style="font-family:Arial,sans-serif;font-size:10px;color:${C.headerSub};margin-left:10px;text-transform:uppercase;letter-spacing:0.8px;">${subtitle}</span>` : ''}
    </td></tr>
  </table>
</td></tr>`;

// colHeaders accepts array of {label, align} — aligns header text to match data cells
const colHeaders = (cols) => `
<tr style="background:#F9F7F4;">
  ${cols.map((c, i) => {
    const align = c.align || 'left';
    const padLeft  = (align === 'left' && i === 0) ? '24px' : '12px';
    const padRight = align === 'right' ? '20px' : '12px';
    return `<td style="font-family:Arial,sans-serif;font-size:10px;font-weight:bold;color:${C.label};
      padding:10px ${padRight} 10px ${padLeft};border-bottom:1px solid ${C.divider};
      text-transform:uppercase;letter-spacing:1px;text-align:${align};white-space:nowrap;">${c.label}</td>`;
  }).join('')}
</tr>`;

// Change cell: "was X" + pill both right-aligned, stacked, in a right-aligned block
// Both elements are display:block and text-align:right so they stack flush right
function changeCell(wowObj, prevValue) {
  const wasLine = prevValue !== null
    ? `<span style="display:block;font-family:Arial,sans-serif;font-size:10px;color:#B0A89E;text-align:right;margin-bottom:4px;">was ${fmt(prevValue)}</span>`
    : '';
  const pillLine = `<span style="display:block;text-align:right;">
    <span style="display:inline-block;background:${wowObj.pill};border-radius:12px;padding:3px 8px;
      font-family:Arial,sans-serif;font-size:11px;font-weight:bold;color:${wowObj.pillText};white-space:nowrap;">
      ${wowObj.arrow}&thinsp;${wowObj.text}
    </span>
  </span>`;
  return `<td style="padding:13px 20px 13px 12px;border-bottom:1px solid ${C.divider};vertical-align:middle;">${wasLine}${pillLine}</td>`;
}

// Inline pill (no "was" — used in overview where Last Week column already exists)
function pillOnly(wowObj) {
  return `<span style="display:inline-block;background:${wowObj.pill};border-radius:12px;padding:3px 8px;
    font-family:Arial,sans-serif;font-size:11px;font-weight:bold;color:${wowObj.pillText};white-space:nowrap;">
    ${wowObj.arrow}&thinsp;${wowObj.text}
  </span>`;
}

// Overview row: label(left) / this week(right) / last week(right) / pill(right)
const overviewRow = (label, curr, prev, wowObj, isAlt) => `
<tr style="background:${isAlt ? C.rowAlt : C.rowBase};">
  <td style="font-family:Arial,sans-serif;font-size:13px;color:${C.label};padding:14px 12px 14px 24px;border-bottom:1px solid ${C.divider};width:34%;text-align:left;">${label}</td>
  <td style="font-family:Georgia,serif;font-size:15px;font-weight:bold;color:${C.value};padding:14px 12px;border-bottom:1px solid ${C.divider};width:18%;text-align:right;">${curr}</td>
  <td style="font-family:Arial,sans-serif;font-size:13px;color:${C.prevValue};padding:14px 12px;border-bottom:1px solid ${C.divider};width:18%;text-align:right;">${prev}</td>
  <td style="padding:14px 20px 14px 12px;border-bottom:1px solid ${C.divider};width:30%;text-align:right;">${pillOnly(wowObj)}</td>
</tr>`;

// List row: rank(center) / name(left) / value(right) / change cell(right-stacked)
const listRowWoW = (rank, name, value, wowObj, prevValue, isAlt) => `
<tr style="background:${isAlt ? C.rowAlt : C.rowBase};">
  <td style="font-family:Arial,sans-serif;font-size:12px;color:${C.gold};font-weight:bold;padding:13px 0 13px 24px;border-bottom:1px solid ${C.divider};width:6%;text-align:center;">${rank}</td>
  <td style="font-family:Arial,sans-serif;font-size:13px;color:${C.value};padding:13px 12px;border-bottom:1px solid ${C.divider};text-align:left;">${name}</td>
  <td style="font-family:Georgia,serif;font-size:14px;font-weight:bold;color:${C.value};padding:13px 12px;border-bottom:1px solid ${C.divider};text-align:right;white-space:nowrap;">${value}</td>
  ${changeCell(wowObj, prevValue)}
</tr>`;

// Bar row: label(left) / bar / sessions n+%(right) / change cell(right-stacked)
const barRowWoW = (label, value, total, barColor, wowObj, prevValue, isAlt) => {
  const pct = ((parseInt(value || 0) / total) * 100).toFixed(1);
  const barWidth = Math.min(99, Math.max(1, Math.round(parseFloat(pct))));
  return `
<tr style="background:${isAlt ? C.rowAlt : C.rowBase};">
  <td style="font-family:Arial,sans-serif;font-size:13px;color:${C.value};padding:14px 24px 14px 24px;border-bottom:1px solid ${C.divider};width:22%;text-align:left;">${label}</td>
  <td style="padding:14px 12px;border-bottom:1px solid ${C.divider};width:26%;">
    <table width="100%" cellpadding="0" cellspacing="0"><tr>
      <td style="width:${barWidth}%;background:${barColor};height:6px;border-radius:3px 0 0 3px;font-size:0;line-height:0;"></td>
      <td style="width:${100-barWidth}%;background:#EDE8E2;height:6px;border-radius:0 3px 3px 0;font-size:0;line-height:0;"></td>
    </tr></table>
  </td>
  <td style="font-family:Georgia,serif;font-size:14px;font-weight:bold;color:${C.value};padding:14px 12px;border-bottom:1px solid ${C.divider};text-align:right;white-space:nowrap;width:24%;">
    ${fmt(value)}&thinsp;<span style="font-family:Arial,sans-serif;font-size:11px;color:${C.prevValue};font-weight:normal;">${pct}%</span>
  </td>
  ${changeCell(wowObj, prevValue)}
</tr>`;
};

// ── 6. BUILD ROWS ─────────────────────────────────────────────

const deviceColors = { mobile: '#C9A96E', desktop: '#5C6B73', tablet: '#8C7B6E' };
const deviceLabels = { mobile: 'Mobile', desktop: 'Desktop', tablet: 'Tablet' };

const deviceRows = devices.map((d, i) => {
  const cat = (d.deviceCategory || 'other').toLowerCase();
  const { wow: wowDev, prevValue } = listWoWWithPrev(d, devicesPrev, 'deviceCategory', 'sessions');
  return barRowWoW(deviceLabels[cat] || cat, d.sessions, totalDeviceSessions, deviceColors[cat] || C.gold, wowDev, prevValue, i % 2 !== 0);
}).join('');

const nvrRows = [
  barRowWoW('New Users',       newUsersRow.totalUsers,  totalNvR, '#2D6A4F', wowNewUsers, parseInt(newUsersPrevRow.totalUsers) || null, false),
  barRowWoW('Returning Users', returningRow.totalUsers, totalNvR, C.gold,    wowRetUsers, parseInt(retUsersPrevRow.totalUsers) || null, true),
].join('');

const pageRows = pages.map((p, i) => {
  const { wow: w, prevValue } = listWoWWithPrev(p, pagesPrev, 'unifiedScreenName', 'screen_page_view');
  return listRowWoW(i + 1, p.unifiedScreenName, fmt(p.screen_page_view), w, prevValue, i % 2 !== 0);
}).join('');

const referralRows = referrals.map((r, i) => {
  const { wow: w, prevValue } = listWoWWithPrev(r, referralsPrev, 'sessionSourceMedium', 'sessions');
  return listRowWoW(i + 1, r.sessionSourceMedium, fmt(r.sessions), w, prevValue, i % 2 !== 0);
}).join('');

const eventRows = events.map((e, i) => {
  const { wow: w, prevValue } = listWoWWithPrev(e, eventsPrev, 'eventName', 'event_count');
  return listRowWoW(i + 1, e.eventName, fmt(e.event_count), w, prevValue, i % 2 !== 0);
}).join('');

const countryRows = countries.map((c, i) => {
  const { wow: w, prevValue } = listWoWWithPrev(c, countriesPrev, 'country', 'sessions');
  return listRowWoW(i + 1, c.country, fmt(c.sessions), w, prevValue, i % 2 !== 0);
}).join('');

// ── 7. COLUMN HEADER DEFINITIONS ─────────────────────────────
// align MUST match the text-align of the data cell below it

const hdrsOverview   = [{label:'Metric',align:'left'},{label:'This Week',align:'right'},{label:'Last Week',align:'right'},{label:'Change',align:'right'}];
const hdrsAudience   = [{label:'Segment',align:'left'},{label:'Share',align:'left'},{label:'Users',align:'right'},{label:'Change',align:'right'}];
const hdrsScreens    = [{label:'#',align:'center'},{label:'Screen / Page',align:'left'},{label:'Views',align:'right'},{label:'Change',align:'right'}];
const hdrsTraffic    = [{label:'#',align:'center'},{label:'Source / Medium',align:'left'},{label:'Sessions',align:'right'},{label:'Change',align:'right'}];
const hdrsEvents     = [{label:'#',align:'center'},{label:'Event Name',align:'left'},{label:'Count',align:'right'},{label:'Change',align:'right'}];
const hdrsGeo        = [{label:'#',align:'center'},{label:'Country',align:'left'},{label:'Sessions',align:'right'},{label:'Change',align:'right'}];
const hdrsDevices    = [{label:'Device',align:'left'},{label:'Share',align:'left'},{label:'Sessions',align:'right'},{label:'Change',align:'right'}];

// ── 8. BUILD EMAIL ────────────────────────────────────────────

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1.0">
  <title>Weekly Performance Report</title>
</head>
<body style="margin:0;padding:0;background:${C.bg};font-family:Arial,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:${C.bg};">
<tr><td align="center" style="padding:32px 16px 40px;">

  <table width="600" cellpadding="0" cellspacing="0"
    style="max-width:600px;width:100%;background:${C.card};border-radius:4px;overflow:hidden;box-shadow:0 2px 40px rgba(0,0,0,0.09);">

    <!-- HEADER -->
    <tr>
      <td style="background:${C.headerBg};padding:40px 32px 36px;">
        <table width="100%" cellpadding="0" cellspacing="0"><tr><td>
          <div style="font-family:Arial,sans-serif;font-size:10px;font-weight:bold;color:${C.gold};letter-spacing:2.5px;text-transform:uppercase;margin-bottom:14px;">Analytics Report</div>
          <div style="font-family:Georgia,serif;font-size:28px;font-weight:bold;color:#FFFFFF;line-height:1.2;margin-bottom:10px;letter-spacing:-0.5px;">Weekly Performance<br>Summary</div>
          <div style="font-family:Arial,sans-serif;font-size:13px;color:${C.headerSub};margin-bottom:24px;">${startLabel} &nbsp;—&nbsp; ${endLabel}</div>
          <div style="height:1px;background:linear-gradient(to right,${C.gold},transparent);margin-bottom:24px;"></div>
          <table width="100%" cellpadding="0" cellspacing="0"><tr>
            <td style="text-align:center;padding:0 12px 0 0;width:25%;border-right:1px solid #2E2E2E;">
              <div style="font-family:Georgia,serif;font-size:22px;font-weight:bold;color:#FFFFFF;">${fmt(currentWeek.totalUsers)}</div>
              <div style="font-family:Arial,sans-serif;font-size:10px;color:${C.headerSub};margin-top:4px;text-transform:uppercase;letter-spacing:0.8px;">Users</div>
              <div style="font-family:Arial,sans-serif;font-size:11px;font-weight:bold;color:${wow.totalUsers.color};margin-top:5px;">${wow.totalUsers.arrow} ${wow.totalUsers.text}</div>
            </td>
            <td style="text-align:center;padding:0 12px;width:25%;border-right:1px solid #2E2E2E;">
              <div style="font-family:Georgia,serif;font-size:22px;font-weight:bold;color:#FFFFFF;">${fmt(currentWeek.sessions)}</div>
              <div style="font-family:Arial,sans-serif;font-size:10px;color:${C.headerSub};margin-top:4px;text-transform:uppercase;letter-spacing:0.8px;">Sessions</div>
              <div style="font-family:Arial,sans-serif;font-size:11px;font-weight:bold;color:${wow.sessions.color};margin-top:5px;">${wow.sessions.arrow} ${wow.sessions.text}</div>
            </td>
            <td style="text-align:center;padding:0 12px;width:25%;border-right:1px solid #2E2E2E;">
              <div style="font-family:Georgia,serif;font-size:22px;font-weight:bold;color:#FFFFFF;">${fmtPct(currentWeek.bounce_rate)}</div>
              <div style="font-family:Arial,sans-serif;font-size:10px;color:${C.headerSub};margin-top:4px;text-transform:uppercase;letter-spacing:0.8px;">Bounce</div>
              <div style="font-family:Arial,sans-serif;font-size:11px;font-weight:bold;color:${wow.bounceRate.color};margin-top:5px;">${wow.bounceRate.arrow} ${wow.bounceRate.text}</div>
            </td>
            <td style="text-align:center;padding:0 0 0 12px;width:25%;">
              <div style="font-family:Georgia,serif;font-size:22px;font-weight:bold;color:#FFFFFF;">${formatDuration(currentWeek.average_session_dur)}</div>
              <div style="font-family:Arial,sans-serif;font-size:10px;color:${C.headerSub};margin-top:4px;text-transform:uppercase;letter-spacing:0.8px;">Duration</div>
              <div style="font-family:Arial,sans-serif;font-size:11px;font-weight:bold;color:${wow.avgDuration.color};margin-top:5px;">${wow.avgDuration.arrow} ${wow.avgDuration.text}</div>
            </td>
          </tr></table>
        </td></tr></table>
      </td>
    </tr>

    <!-- BODY -->
    <tr><td style="padding:0;background:${C.bg};">
      <table width="100%" cellpadding="0" cellspacing="0">

        ${sectionGap}

        <!-- AI SUMMARY -->
        ${formattedAiSummary ? `
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            <tr><td style="padding:20px 24px 14px;border-bottom:2px solid ${C.gold};">
              <span style="font-family:Georgia,serif;font-size:15px;font-weight:bold;color:${C.sectionText};letter-spacing:0.3px;">AI Executive Summary</span>
              <span style="font-family:Arial,sans-serif;font-size:10px;color:${C.headerSub};margin-left:10px;text-transform:uppercase;letter-spacing:0.8px;">Generated by Gemini</span>
            </td></tr>
            <tr><td style="padding:20px 24px 24px;background:#FDFCFB;">${formattedAiSummary}</td></tr>
          </table>
        </td></tr>
        ${sectionGap}` : ''}

        <!-- OVERVIEW -->
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Overview', `vs ${prevStartLabel} – ${prevEndLabel}`)}
            ${colHeaders(hdrsOverview)}
            ${overviewRow('Total Users',           fmt(currentWeek.totalUsers),                     fmt(previousWeek.totalUsers),                     wow.totalUsers,  false)}
            ${overviewRow('Sessions',              fmt(currentWeek.sessions),                       fmt(previousWeek.sessions),                       wow.sessions,    true)}
            ${overviewRow('New Users',             fmt(currentWeek.new_users),                      fmt(previousWeek.new_users),                      wow.newUsers,    false)}
            ${overviewRow('Bounce Rate',           fmtPct(currentWeek.bounce_rate),                 fmtPct(previousWeek.bounce_rate),                 wow.bounceRate,  true)}
            ${overviewRow('Avg. Session Duration', formatDuration(currentWeek.average_session_dur), formatDuration(previousWeek.average_session_dur), wow.avgDuration, false)}
          </table>
        </td></tr>

        ${sectionGap}

        <!-- AUDIENCE -->
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Audience', 'New vs Returning · WoW')}
            ${colHeaders(hdrsAudience)}
            ${nvrRows}
          </table>
        </td></tr>

        ${sectionGap}

        <!-- TOP SCREENS -->
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Top Screens', 'By views · WoW')}
            ${colHeaders(hdrsScreens)}
            ${pageRows}
          </table>
        </td></tr>

        ${sectionGap}

        <!-- TRAFFIC SOURCES -->
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Traffic Sources', 'Top channels · WoW')}
            ${colHeaders(hdrsTraffic)}
            ${referralRows}
          </table>
        </td></tr>

        ${sectionGap}

        <!-- TOP EVENTS -->
        ${events.length > 0 ? `
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Top Events', 'User interactions · WoW')}
            ${colHeaders(hdrsEvents)}
            ${eventRows}
          </table>
        </td></tr>
        ${sectionGap}` : ''}

        <!-- GEOGRAPHY -->
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Geography', 'Top 5 countries · WoW')}
            ${colHeaders(hdrsGeo)}
            ${countryRows}
          </table>
        </td></tr>

        ${sectionGap}

        <!-- DEVICES -->
        <tr><td colspan="5" style="padding:0;background:${C.card};">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${sectionHeader('Devices', 'By device category · WoW')}
            ${colHeaders(hdrsDevices)}
            ${deviceRows}
          </table>
        </td></tr>

        ${sectionGap}

      </table>
    </td></tr>

    <!-- FOOTER -->
    <tr>
      <td style="background:${C.footerBg};padding:32px;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr><td style="padding-bottom:16px;">
            <div style="height:1px;background:linear-gradient(to right,${C.gold},transparent);margin-bottom:20px;"></div>
            <table width="100%" cellpadding="0" cellspacing="0"><tr>
              <td>
                <div style="font-family:Georgia,serif;font-size:14px;color:#FFFFFF;font-weight:bold;margin-bottom:4px;">AppStoneLab Technologies</div>
                <a href="https://appstonelab.com" style="font-family:Arial,sans-serif;font-size:11px;color:${C.gold};text-decoration:none;">appstonelab.com</a>
              </td>
              <td style="text-align:right;vertical-align:top;">
                <div style="font-family:Arial,sans-serif;font-size:10px;color:${C.footerText};line-height:1.8;">
                  ${startLabel} — ${endLabel}<br>Google Analytics 4<br>
                  <a href="#" style="color:${C.footerText};text-decoration:underline;">Unsubscribe</a>
                </div>
              </td>
            </tr></table>
          </td></tr>
          <tr><td>
            <div style="font-family:Arial,sans-serif;font-size:10px;color:#3A3A3A;line-height:1.6;">
              This report is automatically generated every Monday via n8n workflow automation. Data reflects the 7-day period ending ${endLabel}.
            </div>
          </td></tr>
        </table>
      </td>
    </tr>

  </table>
</td></tr>
</table>
</body>
</html>`;

// ── 9. OUTPUT ─────────────────────────────────────────────────

return [{
  json: {
    subject: `Weekly Performance Report — ${startLabel} to ${endLabel}`,
    html,
    recipients: 'user@example.com',
    _debug: {
      currentWeekUsers: currentWeek.totalUsers,
      previousWeekUsers: previousWeek.totalUsers,
      pagesReturned: pages.length,
      eventsReturned: events.length,
      devicesReturned: devices.length,
      aiSummaryLength: aiSummary.length,
    }
  }
}];

